const Modal = () => {

  const [open, setOpen] = useState(false);

  const openModal = (e) => {

    if (e.target.classList.contains('info-close-btn') || e.target.classList.contains('apod-url')) return;
    
    if (open) {
      setOpen(false);
    } else {
      setOpen(true);
    }
  }

  const closeModal = (e) => {
    if (!e.target.classList.contains('modal-img')) {
      setOpen(false);
    }
  }

  return (
    <div className={open ? 'modal-overlay open' : 'modal-overlay'} onClick={closeModal}>
      <img src={obj.url} alt="" className="modal-img"/>
    </div>
  )
}

export default Modal
